import osfrom flask import Flask, request, jsonifyfrom telethon import TelegramClientimport asyncioimport base64from io import BytesIOfrom tg_messages import get_chat_previewfrom tg_search import search_chatsfrom tg_send import send_messagesfrom tg_utils import get_chats_infofrom tg_utils import get_all_foldersapp = Flask(__name__)# Загрузка конфигурации из переменных окруженияAPI_ID = int(os.getenv("API_ID", 30101072))API_HASH = os.getenv("API_HASH", "e0f3d73a25cc1c3084fb3341fb526955")PHONE = os.getenv("PHONE", "+79204962556")DEVICE_PARAMS = {    "device_model": "Samsung S23 Ultra",    "system_version": "Android 13",    "app_version": "9.6.1",    "lang_code": "en",    "system_lang_code": "en-US"}client = TelegramClient(    'session_web',    API_ID,    API_HASH,    device_model=DEVICE_PARAMS["device_model"],    system_version=DEVICE_PARAMS["system_version"],    app_version=DEVICE_PARAMS["app_version"],    lang_code=DEVICE_PARAMS["lang_code"],    system_lang_code=DEVICE_PARAMS["system_lang_code"])loop = asyncio.new_event_loop()asyncio.set_event_loop(loop)def run_async(coro):    return loop.run_until_complete(coro)async def auth():    await client.start(PHONE)    print("✅ Telegram готов")run_async(auth())async def get_avatar(entity):    """Асинхронное получение аватара без записи на диск"""    try:        buffer = BytesIO()        await client.download_profile_photo(entity, file=buffer)        if buffer.getvalue():            return base64.b64encode(buffer.getvalue()).decode('utf-8')    except Exception as e:        print(f"Avatar error: {e}")    return None@app.route('/api/chats/all')def get_all_chats():    async def fetch():        result = []        async for d in client.iter_dialogs():            # Получаем username или телефон            username = getattr(d.entity, 'username', None)            if not username:                phone = getattr(d.entity, 'phone', None)                if phone:                    username = phone            result.append({                'id': d.id,                'name': d.name,                'username': username,                'avatar': await get_avatar(d.entity)            })            if len(result) % 100 == 0:                print(f"Загружено {len(result)} чатов...")        return result    try:        data = run_async(fetch())        print(f"Всего загружено чатов: {len(data)}")        return jsonify(data)    except Exception as e:        print(f"Ошибка /api/chats/all: {e}")        return jsonify([]), 500@app.route('/api/search', methods=['POST'])def search():    try:        data = request.json        print(f"🔵 Получены данные от Java: {data}")        params = {            'term': data.get('term', 'Java'),            'maxFoundCount': data.get('maxFoundCount', 10),            'minDiffDaysCount': data.get('minDiffDaysCount', 7),            'botType': data.get('botType', 'PERSONAL'),            'groupType': data.get('groupType', 'PERSONAL'),            'excludeChatIds': data.get('excludeChatIds', []),            'messagesCount': data.get('messagesCount', 0)        }        print(f"🔵 Параметры поиска: {params}")        found_chats = run_async(search_chats(client, params))        # Добавляем аватары к найденным чатам        async def add_avatars(chats):            for chat in chats:                try:                    entity = await client.get_entity(chat['id'])                    chat['avatar'] = await get_avatar(entity)                    chat['folders'] = await get_chat_folders(client, chat['id'])                except Exception as e:                    print(f"Avatar error for {chat.get('name')}: {e}")                    chat['avatar'] = None                    chat['folders'] = []            return chats        found_chats = run_async(add_avatars(found_chats))        return jsonify(found_chats)    except Exception as e:        print(f"🔴 Ошибка в search: {e}")        return jsonify([]), 500@app.route('/api/chat-preview/<chat_id>')def chat_preview(chat_id):    try:        chat_id = int(chat_id)    except ValueError:        return jsonify({'error': 'Invalid chat_id'}), 400    limit = request.args.get('limit', default=None, type=int)    if limit == 0:        limit = None    try:        result = run_async(get_chat_preview(client, chat_id, limit))        return jsonify(result)    except Exception as e:        print(f"Ошибка preview: {e}")        return jsonify({'messages': []}), 500@app.route('/api/send_bulk_messages', methods=['POST'])def send_bulk_messages():    data = request.json    print(f"🔵 Получены данные: {data}")  # добавить    chat_ids = data.get('contactIds', [])    message_text = data.get('messageText', '')    delay = data.get('delaySeconds', 2)    only_new_chats = data.get('onlyNewChats', False)    if not chat_ids:        return jsonify({'error': 'Нет чатов'}), 400    if not message_text:        return jsonify({'error': 'Нет текста'}), 400    try:        results = run_async(send_messages(client, chat_ids, message_text, delay, only_new_chats))        success_count = len([r for r in results if r['status'] == 'success'])        skipped_count = len([r for r in results if r['status'] == 'skipped'])        error_count = len([r for r in results if r['status'] == 'error'])        return jsonify({            'total': len(chat_ids),            'success': success_count,            'skipped': skipped_count,            'error': error_count,            'results': results        })    except Exception as e:        return jsonify({'error': str(e)}), 500@app.route('/api/export/<int:chat_id>')def export_chat(chat_id):    async def export():        chat_name = str(chat_id)        async for d in client.iter_dialogs():            if d.id == chat_id:                chat_name = d.name                break        messages = []        async for m in client.iter_messages(chat_id, limit=5000):            messages.append({'id': m.id, 'date': str(m.date), 'text': m.text[:500] if m.text else None})        os.makedirs('exports', exist_ok=True)        filename = f'exports/{chat_name.replace("/", "_").replace(" ", "_")}.json'        with open(filename, 'w', encoding='utf-8') as f:            import json            json.dump({                'chat_id': chat_id,                'chat_name': chat_name,                'total_messages': len(messages),                'messages': messages            }, f, ensure_ascii=False, indent=2)        return {'filename': filename, 'total': len(messages)}    try:        result = run_async(export())        return jsonify(result)    except Exception as e:        return jsonify({'error': str(e)}), 500@app.route('/api/folders', methods=['GET'])def get_folders():    try:        folders = run_async(get_all_folders(client))        return jsonify(folders)    except Exception as e:        print(f"❌ Ошибка получения папок: {e}")        return jsonify([]), 500@app.route('/api/chats/info', methods=['POST'])def get_chats_info_endpoint():    try:        data = request.json        chat_ids = data.get('chat_ids', [])        if not chat_ids:            return jsonify({'error': 'Нет ID чатов'}), 400        print(f"🔵 Запрос информации о {len(chat_ids)} чатах")        results = run_async(get_chats_info(client, chat_ids))        return jsonify({            'total': len(chat_ids),            'success': len([r for r in results if r.get('name') is not None]),            'error': len([r for r in results if r.get('error')]),            'results': results        })    except Exception as e:        print(f"🔴 Ошибка в /api/chats/info: {e}")        return jsonify({'error': str(e)}), 500if __name__ == '__main__':    print("🚀 Сервер на http://localhost:8081")    app.run(debug=False, port=8081, threaded=False)